SELECT id, order_no, user_id, address_id, consignee, phone, address_detail, total_amount, discount_amount, pay_amount, pay_status, order_status, create_time, update_time, logistics_company, logistics_no FROM orders WHERE user_id = #{userId}
AND order_status = #{queryDTO.orderStatus}
AND order_no LIKE CONCAT('%', #{queryDTO.orderNo}, '%')
ORDER BY create_time DESC

SELECT id, order_no, user_id, address_id, consignee, phone, address_detail,
       total_amount, discount_amount, pay_amount, pay_status, order_status,
       create_time, update_time, logistics_company, logistics_no
FROM orders
WHERE 1=1

    AND user_id = #{userId}


    AND order_no LIKE CONCAT('%', #{orderNo}, '%')


    AND order_status = #{orderStatus}


    AND pay_status = #{payStatus}


    AND create_time >= #{startTime}


    AND create_time <= #{endTime}

ORDER BY ${sortBy} ${order}

SELECT * FROM orders
WHERE order_status = #{status}
AND ship_time < DATE_SUB(NOW(), INTERVAL #{days} DAY)
